#include<bits/stdc++.h>
using namespace std;
const int N=4000010;
int n,m,k,p[N][2],a[N],tot;
struct two_sat
{
    int low[N*2],dfn[N*2],dfncnt,scccnt,color[N*2];
    bool instk[N*2];
    vector<int> mp[N*2];
    stack<int> stk;
    void add(int x,int y)
    {
        mp[x].push_back(y);
    }
    void tarjan(int x)
    {
        low[x]=dfn[x]=++dfncnt;
        stk.push(x);
        instk[x]=1;
        for(int v:mp[x])
        {
            if(!dfn[v])
            {
                tarjan(v);
                low[x]=min(low[x],low[v]);
            }
            else if(instk[v])
            {
                low[x]=min(low[x],dfn[v]);
            }
        }
        if(low[x]==dfn[x])
        {
            scccnt++;
            int top;
            do
            {
                top=stk.top();
                stk.pop();
                color[top]=scccnt;
                instk[top]=0;
            }while(top!=x);
        }
    }
    void solve()
    {
        for(int i=0;i<=tot;i++)
        {
            if(!dfn[i])
            {
                tarjan(i);
            }
        }
    }
    bool possible()
    {
        for(int i=1;i<=n;i++)
        {
            if(color[(i-1)*2]==color[(i-1)*2+1])
            {
                return false;
            }
        }
        return true;
    }
    bool getans(int x)
    {
        return color[x]<color[x+n];
    }
}t;
int main()
{
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        t.add((x-1)*2+1,(y-1)*2);
        t.add((y-1)*2+1,(x-1)*2);
    }
    tot=n*2;
    for(int j=1;j<=k;j++)
    {
        int t;
        scanf("%d",&t);
        for(int i=1;i<=t;i++)
        {
            scanf("%d",&a[i]);
            p[a[i]][0]=++tot;
            p[a[i]][1]=++tot;
            ::t.add((a[i]-1)*2,p[a[i]][0]);
            ::t.add(p[a[i]][1],(a[i]-1)*2+1);
        }
        for(int i=2;i<=t;i++)
        {
            int d1=a[i-1],d2=a[i];
            ::t.add(p[d1][0],p[d2][0]);
            ::t.add(p[d2][1],p[d1][1]);
            ::t.add(p[d1][0],(d2-1)*2+1);
            ::t.add((d2-1)*2,p[d1][1]);
        }
    }
    t.solve();
    if(t.possible())
    {
        printf("TAK");
    }
    else
    {
        printf("NIE");
    }
    return 0;
}
